pub type SaleDatum {
  seller: VerificationKeyHash,
  price_lovelace: Int,
}

pub type SaleRedeemer {
  Buy
  Cancel
}

validator nft_sale {
  fn spend(datum: Option<SaleDatum>, redeemer: SaleRedeemer, _own_ref: OutputReference, self: Transaction) -> Bool {
    when datum is {
      None -> False
      Some(d) ->
        when redeemer is {
          Cancel -> list.has(self.extra_signatories, d.seller)
          Buy -> {
            let min_price = 5_000_000
            let required = if d.price_lovelace > min_price { d.price_lovelace } else { min_price }
            list.any(
              self.outputs,
              fn(o) {
                when o.address.payment_credential is {
                  VerificationKey(vk) -> vk == d.seller && assets.lovelace_of(o.value) >= required
                  _ -> False
                }
              },
            )
          }
        }
    }
  }
}

use cardano/assets
use cardano/transaction.{OutputReference, Transaction}
