use aiken/crypto.{VerificationKeyHash}

pub type RoyaltyDatum {
  seller: VerificationKeyHash,
  royalty_address: VerificationKeyHash,
  sale_price: Int,
}

pub type RoyaltyRedeemer {
  Purchase
  Refund
}

validator royalty_split {
  fn spend(datum: Option<RoyaltyDatum>, redeemer: RoyaltyRedeemer, _own_ref: OutputReference, self: Transaction) -> Bool {
    when datum is {
      None -> False
      Some(d) ->
        when redeemer is {
          Refund -> list.has(self.extra_signatories, d.seller)
          Purchase -> {
            let royalty_amount = d.sale_price * 10 / 100
            let seller_amount = d.sale_price - royalty_amount
            let seller_paid =
              list.any(
                self.outputs,
                fn(o) {
                  when o.address.payment_credential is {
                    VerificationKey(vk) -> vk == d.seller && assets.lovelace_of(o.value) >= seller_amount
                    _ -> False
                  }
                },
              )
            let royalty_paid =
              list.any(
                self.outputs,
                fn(o) {
                  when o.address.payment_credential is {
                    VerificationKey(vk) -> vk == d.royalty_address && assets.lovelace_of(o.value) >= royalty_amount
                    _ -> False
                  }
                },
              )
            seller_paid && royalty_paid
          }
        }
    }
  }
}

