use cardano/assets
use cardano/transaction.{OutputReference, Transaction}
use aiken/collection/list
use aiken/crypto.{VerificationKeyHash}

pub type ThreeWayDatum {
  seller: VerificationKeyHash,
  creator: VerificationKeyHash,
  platform: VerificationKeyHash,
  total_price: Int,
}

pub type ThreeWayRedeemer {
  Execute
  Cancel
}

validator three_way_split {
  fn spend(datum: Option<ThreeWayDatum>, redeemer: ThreeWayRedeemer, _own_ref: OutputReference, self: Transaction) -> Bool {
    when datum is {
      None -> False
      Some(d) ->
        when redeemer is {
          Cancel -> list.has(self.extra_signatories, d.seller)
          Execute -> {
            let creator_cut = d.total_price * 15 / 100
            let platform_cut = d.total_price * 5 / 100
            let seller_cut = d.total_price - creator_cut - platform_cut
            let seller_ok =
              list.any(self.outputs, fn(o) {
                when o.address.payment_credential is {
                  VerificationKey(vk) -> vk == d.seller && assets.lovelace_of(o.value) >= seller_cut
                  _ -> False
                }
              })
            let creator_ok =
              list.any(self.outputs, fn(o) {
                when o.address.payment_credential is {
                  VerificationKey(vk) -> vk == d.creator && assets.lovelace_of(o.value) >= creator_cut
                  _ -> False
                }
              })
            let platform_ok =
              list.any(self.outputs, fn(o) {
                when o.address.payment_credential is {
                  VerificationKey(vk) -> vk == d.platform && assets.lovelace_of(o.value) >= platform_cut
                  _ -> False
                }
