                  _ -> False
                }
              })
            below_goal && donor_signed && refund_paid
          }
          Collect -> {
            let minimum_goal = 500_000_000
            let effective_goal = if d.goal >= minimum_goal { d.goal } else { minimum_goal }
            let goal_reached = d.donated >= effective_goal
            let charity_paid =
              list.any(self.outputs, fn(o) {
                when o.address.payment_credential is {
                  VerificationKey(vk) -> vk == d.charity && assets.lovelace_of(o.value) >= d.donated
                  _ -> False
                }
              })
            goal_reached && charity_paid
          }
        }
    }
  }
}

