  treasury: VerificationKeyHash,
  admin1: VerificationKeyHash,
  admin2: VerificationKeyHash,
  price: Int,
}

pub type GovernedSaleRedeemer {
  Sell
  Withdraw
}

validator governed_sale {
  fn spend(datum: Option<GovernedSaleDatum>, redeemer: GovernedSaleRedeemer, _own_ref: OutputReference, self: Transaction) -> Bool {
    when datum is {
      None -> False
      Some(d) ->
        when redeemer is {
          Withdraw -> {
            let both_admins =
              list.has(self.extra_signatories, d.admin1) && list.has(
                self.extra_signatories,
                d.admin2,
              )
            both_admins
          }
          Sell -> {
            let fee = d.price * 4 / 100
            let seller_amount = d.price - fee
            let seller_ok =
              list.any(self.outputs, fn(o) {
                when o.address.payment_credential is {
                  VerificationKey(vk) -> vk == d.seller && assets.lovelace_of(o.value) >= seller_amount
                  _ -> False
                }
              })
            let treasury_ok =
              list.any(self.outputs, fn(o) {
                when o.address.payment_credential is {
                  VerificationKey(vk) -> vk == d.treasury && assets.lovelace_of(o.value) >= fee
                  _ -> False
                }
              })
            seller_ok && treasury_ok
          }
        }
    }
  }
}

