pub type FourWayDatum {
  seller: VerificationKeyHash,
  co_owner: VerificationKeyHash,
  original_artist: VerificationKeyHash,
  platform: VerificationKeyHash,
  price: Int,
}

pub type FourWayRedeemer {
  Buy
  Cancel
}

validator four_way_split {
  fn spend(datum: Option<FourWayDatum>, redeemer: FourWayRedeemer, _own_ref: OutputReference, self: Transaction) -> Bool {
    when datum is {
      None -> False
      Some(d) ->
        when redeemer is {
          Cancel -> list.has(self.extra_signatories, d.seller)
          Buy -> {
            let co_owner_cut = d.price * 20 / 100
            let artist_cut = d.price * 15 / 100
            let platform_cut = d.price * 5 / 100
            let seller_cut = d.price - co_owner_cut - artist_cut - platform_cut
            let seller_ok =
              list.any(self.outputs, fn(o) {
                when o.address.payment_credential is {
                  VerificationKey(vk) -> vk == d.seller && assets.lovelace_of(o.value) >= seller_cut
                  _ -> False
                }
              })
            let co_owner_ok =
              list.any(self.outputs, fn(o) {
                when o.address.payment_credential is {
                  VerificationKey(vk) -> vk == d.co_owner && assets.lovelace_of(o.value) >= co_owner_cut
                  _ -> False
                }
              })
            let artist_ok =
              list.any(self.outputs, fn(o) {
                when o.address.payment_credential is {
                  VerificationKey(vk) -> vk == d.original_artist && assets.lovelace_of(o.value) >= artist_cut
                  _ -> False
                }
              })
            let platform_ok =
              list.any(self.outputs, fn(o) {
                when o.address.payment_credential is {
                  VerificationKey(vk) -> vk == d.platform && assets.lovelace_of(o.value) >= platform_cut
                  _ -> False
                }
              })
            seller_ok && co_owner_ok && artist_ok && platform_ok
          }
        }
    }
  }
}

