validator oracle_price_check {
  spend(
    _datum: Option<Void>,
    redeemer: PriceRedeemer,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(oracle_input) =
      transaction.find_input(self.reference_inputs, redeemer.oracle_ref)
    expect InlineDatum(raw_datum) = oracle_input.output.datum
    expect oracle_datum: OracleDatum = raw_datum
    let oracle_price = oracle_datum.price
    let deviation = redeemer.claimed_price - oracle_price
    let abs_deviation =
      if deviation < 0 {
        -deviation
      } else {
        deviation
      }
    abs_deviation * 100 <= oracle_price * 5
  }
}

