validator loan_repayment_check {
  spend(
    datum: Option<LoanDatum>,
    redeemer: RepayRedeemer,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(loan) = datum
    expect Some(rate_input) =
      transaction.find_input(self.reference_inputs, loan.rate_ref)
    expect InlineDatum(raw) = rate_input.output.datum
    expect rate: InterestRateDatum = raw
    let interest = loan.principal * rate.annual_bps / 10000
    let required_repayment = loan.principal + interest
    let lender_paid =
      list.any(self.outputs, fn(o) {
        when o.address.payment_credential is {
          cardano/address.VerificationKey(pkh) ->
            pkh == loan.lender && assets.lovelace_of(o.value) >= required_repayment
          _ -> False
        }
      })
    lender_paid
  }
}

