validator no_output_to_own_script {
  fn spend(
    _datum: Option<Void>,
    _redeemer: Void,
    own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    let own_script_hash =
      when find_input(self.inputs, own_ref) is {
        Some(input) ->
          when input.output.address.payment_credential is {
            Script(hash) -> hash
            _ -> fail
          }
        None -> fail
      }
    list.all(
      self.outputs,
      fn(o) {
        when o.address.payment_credential is {
          Script(hash) -> hash != own_script_hash
          _ -> True
        }
      },
    )
  }
}

